// Implement CRUD for the accounts resource against the live DB.
// Each function receives the MongoDB db handle from src/db.mjs.
// Call ensureSchema(db) from src/schema.mjs before the first write.
import { ensureSchema } from "./schema.mjs";

const COLLECTION = "accounts";
const TIERS = new Set(["strategic", "midmarket", "standard"]);
const STATUSES = new Set(["active", "at-risk", "churned"]);

function toCreatedAt(value) {
  if (value instanceof Date) return value;
  if (value === undefined) return new Date();
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) throw new Error("invalid createdAt");
  return date;
}

function buildAccountDocument(data) {
  if (typeof data?.accountId !== "string") throw new Error("invalid accountId");
  if (typeof data?.name !== "string") throw new Error("invalid name");
  if (typeof data?.tier !== "string" || !TIERS.has(data.tier)) throw new Error("invalid tier");
  if (typeof data?.status !== "string" || !STATUSES.has(data.status)) throw new Error("invalid status");

  return {
    accountId: data.accountId,
    name: data.name,
    tier: data.tier,
    status: data.status,
    createdAt: toCreatedAt(data.createdAt),
  };
}

function buildPatch(data) {
  const patch = {};
  if (data?.name !== undefined) {
    if (typeof data.name !== "string") throw new Error("invalid name");
    patch.name = data.name;
  }
  if (data?.tier !== undefined) {
    if (typeof data.tier !== "string" || !TIERS.has(data.tier)) throw new Error("invalid tier");
    patch.tier = data.tier;
  }
  if (data?.status !== undefined) {
    if (typeof data.status !== "string" || !STATUSES.has(data.status)) throw new Error("invalid status");
    patch.status = data.status;
  }
  return patch;
}

// Create a accounts record. Return the created document.
export async function createAccounts(db, data) {
  await ensureSchema(db);
  const collection = db.collection(COLLECTION);
  const document = buildAccountDocument(data);
  await collection.deleteMany({ accountId: document.accountId });
  const result = await collection.insertOne(document);
  return { _id: result.insertedId, ...document };
}

// Read a accounts by its id. Return the document or null.
export async function getAccounts(db, id) {
  return db.collection(COLLECTION).findOne({ accountId: id });
}

// Update a accounts by id with partial data. Return the updated document.
export async function updateAccounts(db, id, data) {
  await ensureSchema(db);
  const collection = db.collection(COLLECTION);
  const patch = buildPatch(data);
  if (Object.keys(patch).length === 0) {
    return collection.findOne({ accountId: id });
  }
  const result = await collection.findOneAndUpdate(
    { accountId: id },
    { $set: patch },
    { returnDocument: "after" },
  );
  return result;
}

// Delete a accounts by id. Return true if deleted.
export async function deleteAccounts(db, id) {
  await ensureSchema(db);
  const result = await db.collection(COLLECTION).deleteOne({ accountId: id });
  return result.deletedCount > 0;
}

// Create the accounts collection with a validator.
// Export an async function ensureSchema(db) that creates the collection
// with a JSON schema validator matching the accounts fields.
//
// Fields:
//   accountId: string (required)
//   name: string (required)
